import json
import os
import boto3

s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")


def lambda_handler(event, context):
    action = event.get("action", "health")

    if action == "health":
        return _response(200, {"status": "ok", "service": os.getenv("SERVICE_NAME", "shared-role-lambda")})

    if action == "s3_put":
        bucket = os.environ["S3_BUCKET"]
        key = event["key"]
        body = event.get("body", "")
        s3.put_object(Bucket=bucket, Key=key, Body=body.encode("utf-8"))
        return _response(200, {"message": "object stored", "bucket": bucket, "key": key})

    if action == "dynamodb_put":
        table_name = os.environ["DDB_TABLE"]
        item = event["item"]
        table = dynamodb.Table(table_name)
        table.put_item(Item=item)
        return _response(200, {"message": "item stored", "table": table_name})

    if action == "sns_publish":
        topic_arn = os.environ["SNS_TOPIC_ARN"]
        message = event.get("message", "default message")
        result = sns.publish(TopicArn=topic_arn, Message=message)
        return _response(200, {"message": "published", "message_id": result["MessageId"]})

    if action == "sqs_send":
        queue_url = os.environ["SQS_QUEUE_URL"]
        message = event.get("message", "default message")
        result = sqs.send_message(QueueUrl=queue_url, MessageBody=message)
        return _response(200, {"message": "sent", "message_id": result["MessageId"]})

    return _response(400, {"error": f"unsupported action: {action}"})


def _response(status_code, body):
    return {
        "statusCode": status_code,
        "headers": {"Content-Type": "application/json"},
        "body": json.dumps(body),
    }